# Compute macro-average from results
def mmlu_macro_avg(results: dict) -> float:
    mmlu_scores = [
        v['acc_norm']
        for k, v in results['results'].items()
        if k.startswith('mmlu_') and 'acc_norm' in v
    ]
    return sum(mmlu_scores) / len(mmlu_scores) if mmlu_scores else 0.0
